class Solution {
public:
    int nthUglyNumber(int n) {
        vector<int> uglyNumbers(1, 1);
        int i2 = 0, i3 = 0, i5 = 0;
        while (uglyNumbers.size() < n) {
            int next2 = uglyNumbers[i2] * 2, next3 = uglyNumbers[i3] * 3, next5 = uglyNumbers[i5] * 5;
            int nextUgly = min({next2, next3, next5});
            if (nextUgly == next2) i2++;
            if (nextUgly == next3) i3++;
            if (nextUgly == next5) i5++;
            uglyNumbers.push_back(nextUgly);
        }
        return uglyNumbers.back();
    }
};
efficiency: HIGH
time complexity: O(n)
space complexity: O(n)
energy implications: LOW
explanation: Uses dynamic programming to generate ugly numbers sequentially, maintaining pointers for the next multiples of 2, 3, and 5, ensuring the sequence is generated in ascending order without duplicates.
